--
-- Table structure for table `companies`
--

DROP TABLE IF EXISTS `companies`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `companies` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `is_lessor` tinyint(1) NOT NULL DEFAULT '0',
  `is_lessee` tinyint(1) NOT NULL DEFAULT '0',
  `is_carrier` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Является ли компания перевозчиком',
  `is_platform` tinyint(1) NOT NULL DEFAULT '0',
  `legal_type` enum('ip','ooo') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ooo',
  `legal_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tax_system` enum('vat','no_vat') COLLATE utf8mb4_unicode_ci NOT NULL,
  `inn` varchar(12) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kpp` varchar(9) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ogrn` varchar(15) COLLATE utf8mb4_unicode_ci NOT NULL,
  `okpo` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `legal_address` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `actual_address` text COLLATE utf8mb4_unicode_ci,
  `bank_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `bank_account` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `bik` varchar(9) COLLATE utf8mb4_unicode_ci NOT NULL,
  `correspondent_account` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `director_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `contacts` text COLLATE utf8mb4_unicode_ci,
  `status` enum('pending','verified','rejected') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `credit_limit` decimal(15,2) NOT NULL DEFAULT '0.00',
  `current_debt` decimal(15,2) NOT NULL DEFAULT '0.00',
  `rejection_reason` text COLLATE utf8mb4_unicode_ci,
  `verified_at` timestamp NULL DEFAULT NULL,
  `1c_guid` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `1c_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=46 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

