--
-- Table structure for table `completion_acts`
--

DROP TABLE IF EXISTS `completion_acts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `completion_acts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `order_id` bigint unsigned NOT NULL,
  `waybill_id` bigint unsigned NOT NULL,
  `act_date` date NOT NULL COMMENT 'Дата составления акта',
  `service_start_date` date NOT NULL,
  `service_end_date` date NOT NULL,
  `total_hours` int unsigned NOT NULL COMMENT 'Общее количество отработанных часов',
  `total_downtime` int unsigned NOT NULL DEFAULT '0' COMMENT 'Общее количество часов простоя',
  `penalty_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `hourly_rate` decimal(10,2) NOT NULL COMMENT 'Почасовая ставка',
  `total_amount` decimal(10,2) NOT NULL COMMENT 'Общая сумма к оплате',
  `prepayment_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `final_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `notes` text COLLATE utf8mb4_unicode_ci COMMENT 'Комментарии',
  `document_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Путь к файлу акта',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `perspective` enum('lessor','lessee') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'lessor',
  `related_completion_act_id` bigint unsigned DEFAULT NULL,
  `parent_order_id` bigint unsigned DEFAULT NULL,
  `upd_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `new_completion_acts_waybill_id_foreign` (`waybill_id`),
  KEY `new_completion_acts_act_date_index` (`act_date`),
  KEY `new_completion_acts_status_index` (`status`),
  KEY `completion_acts_related_completion_act_id_foreign` (`related_completion_act_id`),
  KEY `completion_acts_parent_order_id_foreign` (`parent_order_id`),
  KEY `completion_acts_upd_id_foreign` (`upd_id`),
  CONSTRAINT `completion_acts_parent_order_id_foreign` FOREIGN KEY (`parent_order_id`) REFERENCES `orders` (`id`) ON DELETE SET NULL,
  CONSTRAINT `completion_acts_related_completion_act_id_foreign` FOREIGN KEY (`related_completion_act_id`) REFERENCES `completion_acts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `completion_acts_upd_id_foreign` FOREIGN KEY (`upd_id`) REFERENCES `upds` (`id`) ON DELETE SET NULL,
  CONSTRAINT `new_completion_acts_waybill_id_foreign` FOREIGN KEY (`waybill_id`) REFERENCES `waybills` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `completion_acts`
--

LOCK TABLES `completion_acts` WRITE;
