--
-- Table structure for table `equipment_availability`
--

DROP TABLE IF EXISTS `equipment_availability`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipment_availability` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `equipment_id` bigint unsigned NOT NULL,
  `date` date NOT NULL,
  `status` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'available',
  `expires_at` datetime DEFAULT NULL,
  `order_id` bigint unsigned DEFAULT NULL,
  `reservation_token` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `equipment_availability_order_id_foreign` (`order_id`),
  KEY `equipment_availability_equipment_id_date_index` (`equipment_id`,`date`),
  KEY `equipment_availability_reservation_token_index` (`reservation_token`),
  KEY `equipment_availability_equipment_id_date_status_index` (`equipment_id`,`date`,`status`),
  CONSTRAINT `equipment_availability_equipment_id_foreign` FOREIGN KEY (`equipment_id`) REFERENCES `equipment` (`id`),
  CONSTRAINT `equipment_availability_order_id_foreign` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5632 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

