DROP TABLE IF EXISTS `equipment_rental_terms`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipment_rental_terms` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `equipment_id` bigint unsigned NOT NULL,
  `price_per_hour` decimal(10,2) NOT NULL,
  `price_per_km` decimal(10,2) DEFAULT NULL,
  `min_rental_hours` int NOT NULL DEFAULT '1',
  `delivery_days` int NOT NULL DEFAULT '1',
  `return_policy` text COLLATE utf8mb4_unicode_ci,
  `currency` varchar(3) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'RUB',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `delivery_organized_by_lessor` tinyint(1) NOT NULL DEFAULT '1',
  PRIMARY KEY (`id`),
  UNIQUE KEY `equipment_period_unique` (`equipment_id`),
  CONSTRAINT `equipment_rental_terms_equipment_id_foreign` FOREIGN KEY (`equipment_id`) REFERENCES `equipment` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=75 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
