DROP TABLE IF EXISTS `equipment_specifications`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipment_specifications` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `equipment_id` bigint unsigned NOT NULL,
  `key` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `value` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `weight` decimal(10,2) DEFAULT NULL COMMENT 'Вес в кг',
  `length` decimal(10,2) DEFAULT NULL COMMENT 'Длина в метрах',
  `width` decimal(10,2) DEFAULT NULL COMMENT 'Ширина в метрах',
  `height` decimal(10,2) DEFAULT NULL COMMENT 'Высота в метрах',
  PRIMARY KEY (`id`),
  KEY `equipment_specifications_equipment_id_foreign` (`equipment_id`),
  CONSTRAINT `equipment_specifications_equipment_id_foreign` FOREIGN KEY (`equipment_id`) REFERENCES `equipment` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=501 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
