DROP TABLE IF EXISTS `order_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `order_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `order_id` bigint unsigned NOT NULL,
  `equipment_id` bigint unsigned NOT NULL,
  `rental_term_id` bigint unsigned NOT NULL,
  `quantity` int unsigned NOT NULL DEFAULT '1',
  `base_price` decimal(14,2) NOT NULL,
  `fixed_lessor_price` decimal(10,2) NOT NULL COMMENT 'Фиксированная ставка арендодателя',
  `fixed_customer_price` decimal(10,2) NOT NULL COMMENT 'Фиксированная ставка для арендатора',
  `price_per_unit` decimal(14,2) NOT NULL,
  `platform_fee` decimal(14,2) NOT NULL,
  `discount_amount` decimal(14,2) NOT NULL,
  `total_price` decimal(14,2) NOT NULL,
  `period_count` int unsigned NOT NULL COMMENT 'Количество единиц периода аренды',
  `delivery_cost` decimal(12,2) NOT NULL DEFAULT '0.00',
  `distance_km` decimal(8,2) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `rental_condition_id` bigint unsigned DEFAULT NULL,
  `delivery_from_id` bigint unsigned DEFAULT NULL,
  `delivery_to_id` bigint unsigned DEFAULT NULL,
  `lessor_company_id` bigint unsigned DEFAULT NULL,
  `status` enum('pending','in_delivery','active','completed','cancelled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `proposal_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `order_items_order_id_foreign` (`order_id`),
  KEY `order_items_equipment_id_foreign` (`equipment_id`),
  KEY `order_items_rental_term_id_foreign` (`rental_term_id`),
  KEY `order_items_rental_condition_id_foreign` (`rental_condition_id`),
  KEY `order_items_delivery_from_id_foreign` (`delivery_from_id`),
  KEY `order_items_delivery_to_id_foreign` (`delivery_to_id`),
  KEY `order_items_lessor_company_id_foreign` (`lessor_company_id`),
  KEY `order_items_proposal_id_foreign` (`proposal_id`),
  CONSTRAINT `order_items_delivery_from_id_foreign` FOREIGN KEY (`delivery_from_id`) REFERENCES `locations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `order_items_delivery_to_id_foreign` FOREIGN KEY (`delivery_to_id`) REFERENCES `locations` (`id`) ON DELETE SET NULL,
  CONSTRAINT `order_items_equipment_id_foreign` FOREIGN KEY (`equipment_id`) REFERENCES `equipment` (`id`),
  CONSTRAINT `order_items_lessor_company_id_foreign` FOREIGN KEY (`lessor_company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `order_items_order_id_foreign` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE CASCADE,
  CONSTRAINT `order_items_proposal_id_foreign` FOREIGN KEY (`proposal_id`) REFERENCES `rental_request_responses` (`id`) ON DELETE CASCADE,
  CONSTRAINT `order_items_rental_condition_id_foreign` FOREIGN KEY (`rental_condition_id`) REFERENCES `rental_conditions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `order_items_rental_term_id_foreign` FOREIGN KEY (`rental_term_id`) REFERENCES `equipment_rental_terms` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
