DROP TABLE IF EXISTS `user_notification_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_notification_settings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned NOT NULL,
  `markup_created` tinyint(1) NOT NULL DEFAULT '1',
  `markup_updated` tinyint(1) NOT NULL DEFAULT '1',
  `markup_deleted` tinyint(1) NOT NULL DEFAULT '1',
  `markup_activated` tinyint(1) NOT NULL DEFAULT '1',
  `markup_deactivated` tinyint(1) NOT NULL DEFAULT '0',
  `markup_expired` tinyint(1) NOT NULL DEFAULT '1',
  `markup_bulk_operation` tinyint(1) NOT NULL DEFAULT '1',
  `markup_calculation_error` tinyint(1) NOT NULL DEFAULT '1',
  `markup_daily_report` tinyint(1) NOT NULL DEFAULT '0',
  `email_notifications` tinyint(1) NOT NULL DEFAULT '1',
  `browser_notifications` tinyint(1) NOT NULL DEFAULT '1',
  `push_notifications` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_notification_settings_user_id_unique` (`user_id`),
  CONSTRAINT `user_notification_settings_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
