--
-- Table structure for table `waybill_shifts`
--

DROP TABLE IF EXISTS `waybill_shifts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `waybill_shifts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `waybill_id` bigint unsigned NOT NULL,
  `shift_date` date NOT NULL,
  `operator_id` bigint unsigned NOT NULL,
  `object_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `object_address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `departure_time` time DEFAULT NULL,
  `return_time` time DEFAULT NULL,
  `work_start_time` time DEFAULT NULL,
  `work_end_time` time DEFAULT NULL,
  `odometer_start` int DEFAULT NULL,
  `odometer_end` int DEFAULT NULL,
  `fuel_start` decimal(10,2) DEFAULT NULL,
  `fuel_end` decimal(10,2) DEFAULT NULL,
  `fuel_refilled_liters` decimal(10,2) DEFAULT NULL,
  `fuel_refilled_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hours_worked` decimal(5,2) DEFAULT NULL,
  `downtime_hours` decimal(5,2) DEFAULT NULL,
  `downtime_cause` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `work_description` text COLLATE utf8mb4_unicode_ci,
  `hourly_rate` decimal(10,2) NOT NULL,
  `total_amount` decimal(10,2) DEFAULT NULL,
  `operator_signature_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mechanic_signature_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dispatcher_signature_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `foreman_signature_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `waybill_shifts_waybill_id_foreign` (`waybill_id`),
  KEY `waybill_shifts_operator_id_foreign` (`operator_id`),
  CONSTRAINT `waybill_shifts_operator_id_foreign` FOREIGN KEY (`operator_id`) REFERENCES `operators` (`id`),
  CONSTRAINT `waybill_shifts_waybill_id_foreign` FOREIGN KEY (`waybill_id`) REFERENCES `waybills` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=750 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

